#include <stdio.h>
#include <string.h>

int main() {
    int indent, n;
    if (scanf("%d", &indent) != 1) return 0;
    if (scanf("%d", &n) != 1) return 0;
    getchar(); // consume newline after n
    char buffer[105];
    for (int i = 0; i < n; ++i) {
        if (!fgets(buffer, sizeof(buffer), stdin)) break;
        size_t len = strlen(buffer);
        if (len && buffer[len-1] == '\n') buffer[len-1] = '\0';
        for (int s = 0; s < indent; ++s) putchar(' ');
        printf("%s", buffer);
        if (i + 1 < n) putchar('\n');
    }
    return 0;
}

