    int indent, n;
    if (!(cin >> indent)) return 0;
    if (!(cin >> n)) return 0;
    string line;
    getline(cin, line); // consume endline after n
    for (int i = 0; i < n; ++i) {
        getline(cin, line);
        cout << string(indent, ' ') << line;
        if (i + 1 < n) cout << '\n';
    }
    return 0;
}

